/// <summary>
/// Department: Kq (0x16) | Opcode: 15 | Full: 0x580F
/// sizeof = 379
/// </summary>
[FiestaOpcode(ProtocolCommand.Kq, 15)]
public class PROTO_NC_KQ_W2Z_START_CMD : IFiestaPacketBody
{
    public PROTO_KQ_INFO KQInfo = new();
    public ushort NumOfJoiner;
    public PROTO_NC_KQ_JOINER[] JoinerArray = [];

    public void Read(BinaryReader reader)
    {
        KQInfo.Read(reader);
        NumOfJoiner = reader.ReadUInt16();
        JoinerArray = new PROTO_NC_KQ_JOINER[NumOfJoiner];
        for (int i = 0; i < NumOfJoiner; i++)
        {
            JoinerArray[i] = new PROTO_NC_KQ_JOINER();
            JoinerArray[i].Read(reader);
        }
    }

    public void Write(BinaryWriter writer)
    {
        KQInfo.Write(writer);
        writer.Write(NumOfJoiner);
        for (int i = 0; i < JoinerArray.Length; i++)
            JoinerArray[i].Write(writer);
    }
}

